// Get the original row data from the item that triggered the HTTP request
const originalItem = $('Loop Over Items').item.json;
const gamer_id = originalItem.gamer_id;
const approved_domain = originalItem.approved_domain;
const row_number = originalItem.row_number;

// Get the HTTP response data from the HTTP Request node
let responseData = $input.item.json;

// Initialize the value to store
let visitsValue = null;
let status = 'success';

try {
  // Handle network-level errors wrapped by n8n (e.g., Axios ENOTFOUND)
  if (responseData.error && typeof responseData.error === 'object') {
    status = 'error';
    const err = responseData.error;

    // Only extract title and status
    if (err.title && err.status) {
      visitsValue = `0 - ${err.status} - ${err.title}`;
    } else if (err.status) {
      visitsValue = `0 - ${err.status}`;
    } else {
      visitsValue = `0 - Error`;
    }
  } 
  // Handle API-level errors returned in the JSON
  else if (responseData.error || responseData.errorMessage) {
    status = 'error';
    let errObj = responseData.error || responseData.errorMessage;

    // If error is a string, try parsing as JSON
    if (typeof errObj === 'string') {
      try {
        const parsed = JSON.parse(errObj);

        // Only extract title and status
        if (parsed.title && parsed.status) {
          visitsValue = `0 - ${parsed.status} - ${parsed.title}`;
        } else if (parsed.status) {
          visitsValue = `0 - ${parsed.status}`;
        } else {
          visitsValue = `0 - Error`;
        }
      } catch {
        // If parsing fails, use generic error
        visitsValue = `0 - Error`;
      }
    } else if (errObj && errObj.title && errObj.status) {
      visitsValue = `0 - ${errObj.status} - ${errObj.title}`;
    } else if (errObj && errObj.status) {
      visitsValue = `0 - ${errObj.status}`;
    } else {
      visitsValue = `0 - Error`;
    }
  } 
  else {
    let data = Array.isArray(responseData) ? responseData[0] : responseData;

    // Try Engagements.Visits first
    if (data.Engagments && data.Engagments.Visits !== undefined && data.Engagments.Visits !== null) {
      visitsValue = parseInt(data.Engagments.Visits);
    } 
    // Fallback to latest EstimatedMonthlyVisits
    else if (data.EstimatedMonthlyVisits && typeof data.EstimatedMonthlyVisits === 'object') {
      const dates = Object.keys(data.EstimatedMonthlyVisits).sort().reverse();
      if (dates.length > 0) {
        const latestDate = dates[0];
        visitsValue = data.EstimatedMonthlyVisits[latestDate];
      }
    }

    // Treat 0, "0", null, or undefined as no data
    if (visitsValue === 0 || visitsValue === "0" || visitsValue === null || visitsValue === undefined) {
      status = 'no_data';
      visitsValue = `${visitsValue || 0} - No visits data available`;
    }
  }
} catch (error) {
  status = 'error';
  visitsValue = `0 - Error`;
}

// Return the value to update in the sheet, including row_number for matching
return {
  json: {
    row_number: row_number,
    gamer_id: gamer_id,
    approved_domain: approved_domain,
    updated_similarweb_api_data: visitsValue,
    processing_status: status,
    last_updated: new Date().toISOString()
  }
};

// Get all items from previous node
const items = $input.all();
const results = [];

for (const item of items) {
  // Get the raw response HTML string
  const rawResponse = item.json.solution.response;

  // Extract JSON from inside the <pre> tag
  const preMatch = rawResponse.match(/<pre>([\s\S]*?)<\/pre>/);

  if (preMatch && preMatch[1]) {
    try {
      // Decode HTML entities and parse JSON
      const decoded = preMatch[1]
        .replace(/&amp;/g, '&')
        .replace(/&lt;/g, '<')
        .replace(/&gt;/g, '>')
        .replace(/&quot;/g, '"')
        .replace(/&#039;/g, "'");

      const parsed = JSON.parse(decoded);
      results.push({ json: parsed });
    } catch (e) {
      results.push({ json: { error: 'Failed to parse JSON', details: e.message } });
    }
  } else {
    results.push({ json: { error: 'No <pre> tag found in response' } });
  }
}

return results;
